<script setup>
import { router, useForm } from '@inertiajs/vue3';
import { computed, ref, watch } from 'vue';
import PortalLayout from '../../Layouts/PortalLayout.vue';
import SectionTitle from '../../Components/SectionTitle.vue';
import Modal from '../../Components/Modal.vue';
import ActionIconButton from '../../Components/ActionIconButton.vue';
import { formatDateTime } from '../../lib/date';

const props = defineProps({ sports: Array, categories: Array, regulations: Array, venues: Array, audits: Array, sportFormats: Object, initialTab: String });
const tab = ref(props.initialTab || 'sports');
const regulationModal = ref(false);
const regulationId = ref(null);
const regulationReadOnly = ref(false);
const sportModal = ref(false);
const sportId = ref(null);
const categoryModal = ref(false);
const categoryId = ref(null);
const scoreTemplates = [
  { value: 'rally_point_21_best_of_3', label: 'Rally Point 21 — Best of 3 Game' },
  { value: 'set_points', label: 'Set dan Poin' },
  { value: 'games_points', label: 'Game dan Poin' },
  { value: 'sets_games', label: 'Set dan Game' },
  { value: 'swiss_match_points', label: 'Swiss Match Points' },
  { value: 'goals_2x25_minutes', label: 'Gol — 2 × 25 Menit' },
  { value: 'strokes', label: 'Jumlah Pukulan' },
  { value: 'judge_score', label: 'Nilai Juri' },
  { value: 'fun_games', label: 'Fun Games' },
  { value: 'goals', label: 'Gol' },
  { value: 'match_points', label: 'Poin Pertandingan' },
  { value: 'points', label: 'Poin Umum' },
];
const scoreLabel = (value) => scoreTemplates.find((item) => item.value === value)?.label || value?.replaceAll('_', ' ') || 'Belum diatur';
const formatOptions = computed(() => Object.entries(props.sportFormats || {}));
const formatLabel = (value) => props.sportFormats?.[value] || value?.replaceAll('_', ' ') || 'Belum ditetapkan';
const search = ref(''); const status = ref(''); const sportFilter = ref(''); const perPage = ref(10); const page = ref(1);
watch([tab, search, status, sportFilter, perPage], () => { page.value = 1; });
watch(() => props.initialTab, (value) => { tab.value = value || 'sports'; });
const sportForm = useForm({ code: '', name: '', type: 'sport', default_format: 'knockout', score_template: '', default_max_officials_per_pd: 0, official_roles: '', allow_member_cross_category: false, max_categories_per_member: 0, official_can_compete: false, is_active: true });
watch(() => sportForm.allow_member_cross_category, (allowed) => { sportForm.max_categories_per_member = allowed ? (sportForm.max_categories_per_member === 0 ? '' : sportForm.max_categories_per_member) : 0; });
const categoryForm = useForm({ sport_id: '', code: '', name: '', competition_type: 'individual', min_members: 1, max_members: 1, default_max_teams_per_pd: 1, bracket_enabled: true, sort_order: 0, is_active: true });
const regulationForm = useForm({ sport_id: '', title: '', content: '', document_url: '', is_active: true, schedule: '', venue_id: '', system_text: '', eligibility_text: '', official_note: '', fee_note: '', source_slides: '' });
const activeSports = computed(() => props.sports.filter((item) => item.is_active).length);
const activeCategories = computed(() => props.categories.filter((item) => item.is_active).length);
const tabs = computed(() => [
  { id: 'sports', label: 'Cabor', count: props.sports.length },
  { id: 'categories', label: 'Kategori', count: props.categories.length },
  { id: 'regulations', label: 'Regulasi', count: props.regulations.length },
  { id: 'audit', label: 'Riwayat Perubahan', count: props.audits.length },
]);

const saveSport = () => sportForm.submit(sportId.value ? 'put' : 'post', sportId.value ? `/admin/master-data/sports/${sportId.value}` : '/admin/master-data/sports', { preserveScroll: true, onSuccess: () => { sportForm.reset(); sportModal.value = false; sportId.value = null; } });
const openSport = (sport = null) => { sportForm.reset(); sportForm.clearErrors(); sportId.value = sport?.id || null; if (sport) Object.assign(sportForm, { code: sport.code, name: sport.name, type: sport.type, default_format: sport.default_format || 'knockout', score_template: sport.score_template || '', default_max_officials_per_pd: sport.default_max_officials_per_pd ?? 0, official_roles: (sport.official_roles || []).join(', '), allow_member_cross_category: sport.allow_member_cross_category, max_categories_per_member: sport.allow_member_cross_category ? (sport.max_categories_per_member ?? '') : 0, official_can_compete: sport.official_can_compete, is_active: sport.is_active }); sportModal.value = true; };
const saveCategory = () => categoryForm.submit(categoryId.value ? 'put' : 'post', categoryId.value ? `/admin/master-data/categories/${categoryId.value}` : '/admin/master-data/categories', { preserveScroll: true, onSuccess: () => { categoryForm.reset(); categoryModal.value = false; categoryId.value = null; } });
const openCategory = (category = null) => { categoryForm.reset(); categoryForm.clearErrors(); categoryId.value = category?.id || null; if (category) Object.assign(categoryForm, { sport_id: category.sport_id, code: category.code, name: category.name, competition_type: category.competition_type, min_members: category.min_members, max_members: category.max_members, default_max_teams_per_pd: category.default_max_teams_per_pd ?? 1, bracket_enabled: category.bracket_enabled, sort_order: category.sort_order, is_active: category.is_active }); categoryModal.value = true; };
const saveRegulation = () => regulationForm.submit(regulationId.value ? 'put' : 'post', regulationId.value ? `/admin/master-data/regulations/${regulationId.value}` : '/admin/master-data/regulations', { onSuccess: () => { regulationForm.reset(); regulationModal.value = false; regulationId.value = null; } });
const openRegulation = (item = null, readOnly = false) => { regulationForm.reset(); regulationId.value = item?.id || null; regulationReadOnly.value = readOnly; if (item) { const guide = item.technical_guide || {}; Object.assign(regulationForm, { sport_id: item.sport_id, title: item.title, content: item.content, document_url: item.document_url || '', is_active: item.is_active, schedule: guide.schedule || '', venue_id: guide.venue_id || props.venues.find((venue) => venue.name === guide.venue)?.id || '', system_text: (guide.system || []).join('\n'), eligibility_text: (guide.eligibility || []).join('\n'), official_note: guide.official_note || '', fee_note: guide.fee_note || '', source_slides: guide.source_slides || '' }); } regulationModal.value = true; };
watch(() => regulationForm.sport_id, (sportId) => { if (!sportId || regulationId.value || regulationReadOnly.value) return; const item = props.regulations.find((row) => Number(row.sport_id) === Number(sportId) && row.technical_guide); if (!item) return; const guide = item.technical_guide; regulationForm.title = item.title; regulationForm.content = item.content; regulationForm.schedule = guide.schedule || ''; regulationForm.venue_id = guide.venue_id || props.venues.find((venue) => venue.name === guide.venue)?.id || ''; regulationForm.system_text = (guide.system || []).join('\n'); regulationForm.eligibility_text = (guide.eligibility || []).join('\n'); regulationForm.official_note = guide.official_note || ''; regulationForm.fee_note = guide.fee_note || ''; regulationForm.source_slides = guide.source_slides || ''; });
const deleteSport = (sport) => {
  if (confirm(`Hapus cabor ${sport.name}?`)) router.delete(`/admin/master-data/sports/${sport.id}`, { preserveScroll: true });
};
const updateCategory = (category) => router.put(`/admin/master-data/categories/${category.id}`, category, { preserveScroll: true });
const toggleSport = (sport) => router.put(`/admin/master-data/sports/${sport.id}`, { code: sport.code, name: sport.name, type: sport.type, default_format: sport.default_format, score_template: sport.score_template, default_max_officials_per_pd: sport.default_max_officials_per_pd, official_roles: (sport.official_roles || []).join(', '), allow_member_cross_category: sport.allow_member_cross_category, max_categories_per_member: sport.max_categories_per_member, official_can_compete: sport.official_can_compete, is_active: !sport.is_active }, { preserveScroll: true });
const toggleCategory = (category) => updateCategory({ ...category, is_active: !category.is_active });
const deleteCategory = (category) => confirm(`Hapus kategori ${category.name}?`) && router.delete(`/admin/master-data/categories/${category.id}`, { preserveScroll: true });
const toggleRegulation = (item) => { const guide = item.technical_guide || {}; router.put(`/admin/master-data/regulations/${item.id}`, { title: item.title, content: item.content, document_url: item.document_url || '', is_active: !item.is_active, schedule: guide.schedule || '', venue_id: guide.venue_id || '', system_text: (guide.system || []).join('\n'), eligibility_text: (guide.eligibility || []).join('\n'), official_note: guide.official_note || '', fee_note: guide.fee_note || '', source_slides: guide.source_slides || '' }, { preserveScroll: true }); };
const deleteRegulation = (item) => confirm(`Hapus regulasi ${item.title}?`) && router.delete(`/admin/master-data/regulations/${item.id}`, { preserveScroll: true });
const sourceRows = computed(() => ({ sports: props.sports, categories: props.categories, regulations: props.regulations, audit: props.audits }[tab.value] || []));
const filteredRows = computed(() => sourceRows.value.filter((item) => {
  const text = JSON.stringify(item).toLowerCase();
  return (!search.value || text.includes(search.value.toLowerCase()))
    && (!status.value || String(item.is_active) === status.value)
    && (tab.value !== 'categories' || !sportFilter.value || Number(item.sport_id) === Number(sportFilter.value));
}));
const pageCount = computed(() => Math.max(1, Math.ceil(filteredRows.value.length / perPage.value)));
const visibleRows = computed(() => filteredRows.value.slice((page.value - 1) * perPage.value, page.value * perPage.value));
const sports = computed(() => tab.value === 'sports' ? visibleRows.value : props.sports);
const categories = computed(() => tab.value === 'categories' ? visibleRows.value : props.categories);
const regulations = computed(() => tab.value === 'regulations' ? visibleRows.value : props.regulations);
const audits = computed(() => tab.value === 'audit' ? visibleRows.value : props.audits);
const changeTab = (id) => { tab.value = id; router.get('/admin/master-data', { tab: id }, { preserveState: true, preserveScroll: true, replace: true }); };
</script>

<template>
  <PortalLayout portal="admin">
    <div class="page-head"><SectionTitle eyebrow="Phase 2 · Selesai" title="Master Data Lomba" meta="Sumber data resmi kompetisi" /></div>

    <section class="overview-card">
      <div><span>Master Data</span><h2>Kelola fondasi lomba dari satu tempat.</h2><p>Cabor, kategori, dan regulasi tersimpan terstruktur. Perubahan penting masuk audit secara otomatis.</p></div>
      <dl><div><dt>Cabor Aktif</dt><dd>{{ activeSports }}</dd></div><div><dt>Kategori Aktif</dt><dd>{{ activeCategories }}</dd></div><div><dt>Regulasi</dt><dd>{{ regulations.length }}</dd></div></dl>
    </section>

    <nav class="tabs" aria-label="Master data"><button v-for="item in tabs" :key="item.id" type="button" :class="{ active: tab === item.id }" @click="changeTab(item.id)"><span>{{ item.label }}</span><b>{{ item.count }}</b></button></nav>
    <div :class="['table-tools', { 'with-sport-filter': tab === 'categories' }]"><label><span>Pencarian</span><input v-model="search" placeholder="Cari data…" /></label><label v-if="tab === 'categories'"><span>Cabor</span><select v-model="sportFilter"><option value="">Semua cabor</option><option v-for="sport in props.sports" :key="sport.id" :value="sport.id">{{ sport.name }}</option></select></label><label v-if="tab !== 'audit'"><span>Filter</span><select v-model="status"><option value="">Semua status</option><option value="true">Aktif</option><option value="false">Nonaktif</option></select></label><label><span>Per Halaman</span><select v-model.number="perPage"><option :value="10">10</option><option :value="25">25</option><option :value="50">50</option><option :value="100">100</option></select></label></div>

    <section v-if="tab === 'sports'" class="regulation-master">
      <div class="section-actions"><div><strong>Master Cabor</strong><span>Kelola identitas, format, tipe skor, dan status penggunaan.</span></div><button class="primary-button compact" type="button" @click="openSport()">Tambah Cabor</button></div>
      <Modal :open="sportModal" :title="sportId ? 'Edit Master Cabor' : 'Tambah Master Cabor'" theme="light" @close="sportModal = false">
        <form class="modal-form sport-modal-form" @submit.prevent="saveSport">
          <div class="form-section"><header><span>01</span><div><strong>Identitas Cabor</strong><small>Kode bersifat unik dan dipakai pada integrasi data.</small></div></header><div class="field-pair"><label>Kode Cabor<input v-model="sportForm.code" placeholder="Contoh: MINI-FOOTBALL" required /><small v-if="sportForm.errors.code">{{ sportForm.errors.code }}</small></label><label>Nama Cabor<input v-model="sportForm.name" placeholder="Contoh: Mini Football" required /><small v-if="sportForm.errors.name">{{ sportForm.errors.name }}</small></label></div></div>
          <div class="form-section"><header><span>02</span><div><strong>Format Pertandingan</strong><small>Menjadi nilai awal saat Admin membuat Data Lomba.</small></div></header><div class="field-pair"><label>Tipe<select v-model="sportForm.type"><option value="sport">Cabang Olahraga</option><option value="exhibition">Eksibisi</option></select></label><label>Format Bawaan<select v-model="sportForm.default_format"><option v-for="([value, label]) in formatOptions" :key="value" :value="value">{{ label }}</option></select></label></div><label>Sistem Skor Bawaan<select v-model="sportForm.score_template"><option value="">Belum ditetapkan</option><option v-for="item in scoreTemplates" :key="item.value" :value="item.value">{{ item.label }}</option></select><small>Struktur detail skor akan mengikuti regulasi kompetisi.</small></label></div>
          <div class="form-section registration-defaults"><header><span>03</span><div><strong>Aturan Registrasi Bawaan</strong><small>Disalin ke Data Lomba baru dan masih dapat diubah selama draft.</small></div></header><div class="registration-summary"><div><span>Official per PD</span><strong>{{ sportForm.default_max_officials_per_pd || 0 }}</strong></div><div><span>Rangkap Kategori</span><strong>{{ sportForm.allow_member_cross_category ? 'Diizinkan' : 'Tidak' }}</strong></div><div><span>Official Bertanding</span><strong>{{ sportForm.official_can_compete ? 'Diizinkan' : 'Tidak' }}</strong></div></div><div class="registration-grid"><section class="rule-group"><div class="rule-group-title"><b>01</b><div><strong>Kuota Official</strong><small>Atur jumlah pendamping dan nama peran yang tersedia untuk setiap PD.</small></div></div><label class="rule-field"><span>Maksimal Official per PD</span><input v-model.number="sportForm.default_max_officials_per_pd" type="number" min="0" max="20" required /><small>Isi 0 jika cabor tidak memakai official.</small></label><label class="rule-field"><span>Peran Official</span><input v-model="sportForm.official_roles" placeholder="Contoh: team_manager, coach" /><small>Pisahkan setiap peran dengan tanda koma.</small></label></section><section class="rule-group"><div class="rule-group-title"><b>02</b><div><strong>Kebijakan Peserta</strong><small>Atur rangkap kategori serta keterlibatan official sebagai atlet.</small></div></div><label class="rule-field"><span>Atlet Rangkap Kategori</span><select v-model="sportForm.allow_member_cross_category"><option :value="true">Boleh</option><option :value="false">Tidak boleh</option></select></label><label class="rule-field"><span>Maksimal Kategori per Atlet</span><input v-model.number="sportForm.max_categories_per_member" type="number" min="1" max="20" placeholder="Tanpa batas" :disabled="!sportForm.allow_member_cross_category" /><small>{{ sportForm.allow_member_cross_category ? 'Kosongkan jika tidak dibatasi.' : 'Aktif jika rangkap kategori diperbolehkan.' }}</small></label><label class="rule-field official-policy"><span>Official Boleh Bertanding</span><select v-model="sportForm.official_can_compete"><option :value="false">Tidak boleh</option><option :value="true">Boleh</option></select><small>Terapkan hanya jika regulasi cabor mengizinkan.</small></label></section></div></div>
          <div v-if="sportId" class="form-section"><header><span>04</span><div><strong>Status Penggunaan</strong><small>Nonaktifkan bila cabor tidak lagi boleh dipakai pada data baru.</small></div></header><label class="status-field">Status<select v-model="sportForm.is_active"><option :value="true">Aktif</option><option :value="false">Nonaktif</option></select></label></div>
          <footer><button class="outline-button" type="button" @click="sportModal = false">Batal</button><button class="primary-button compact" :disabled="sportForm.processing">{{ sportForm.processing ? 'Menyimpan…' : sportId ? 'Simpan Perubahan' : 'Tambah Cabor' }}</button></footer>
        </form>
      </Modal>
      <div class="table-card sport-table"><header><div><span>Daftar Master</span><h2>Cabor Tersedia</h2><p>{{ activeSports }} aktif dari {{ props.sports.length }} master cabor.</p></div><b>{{ sports.length }} data</b></header><div class="table-scroll"><table><thead><tr><th>Cabor</th><th>Tipe</th><th>Format</th><th>Sistem Skor</th><th>Status</th><th>Aksi</th></tr></thead><tbody><tr v-for="sport in sports" :key="sport.id"><td><div class="sport-identity"><span>{{ sport.code.slice(0, 2).toUpperCase() }}</span><div><strong>{{ sport.name }}</strong><small>{{ sport.code }} · {{ sport.categories_count }} kategori · {{ sport.regulations_count }} regulasi</small></div></div></td><td><span class="type-badge">{{ sport.type === 'exhibition' ? 'Eksibisi' : 'Cabang Olahraga' }}</span></td><td><span class="format-value">{{ formatLabel(sport.default_format) }}</span></td><td><span class="score-value">{{ scoreLabel(sport.score_template) }}</span></td><td><span :class="['status-badge', sport.is_active ? 'active' : 'inactive']">{{ sport.is_active ? 'Aktif' : 'Nonaktif' }}</span></td><td><div class="row-actions"><ActionIconButton icon="edit" label="Edit cabor" @click="openSport(sport)" /><ActionIconButton icon="power" :label="sport.is_active ? 'Nonaktifkan cabor' : 'Aktifkan cabor'" :tone="sport.is_active ? 'inactive' : 'active'" @click="toggleSport(sport)" /><ActionIconButton icon="delete" label="Hapus cabor" tone="danger" :disabled="sport.is_active || !!sport.categories_count || !!sport.regulations_count || !!sport.events_count" @click="deleteSport(sport)" /></div></td></tr><tr v-if="!sports.length"><td colspan="6" class="empty-row">Data cabor tidak ditemukan.</td></tr></tbody></table></div></div>
    </section>

    <section v-else-if="tab === 'categories'" class="regulation-master">
      <div class="section-actions"><div><strong>Master Kategori</strong><span>Kelola kategori, kuota pemain, dan status penggunaan.</span></div><button class="primary-button compact" type="button" @click="openCategory()">Tambah Kategori</button></div>
      <Modal :open="categoryModal" :title="categoryId ? 'Ubah Master Kategori' : 'Tambah Master Kategori'" theme="light" @close="categoryModal = false">
        <form class="form-card category-modal-form" @submit.prevent="saveCategory"><header><span>{{ categoryId ? 'Ubah Data' : 'Data Baru' }}</span><h2>{{ categoryId ? 'Ubah Kategori' : 'Tambah Kategori' }}</h2><p>Atur kuota team dan jumlah pemain. Nilai ini menjadi bawaan Data Lomba.</p></header><div class="form-body"><label>Cabor<select v-model="categoryForm.sport_id" required><option value="">Pilih cabor</option><option v-for="sport in props.sports" :key="sport.id" :value="sport.id">{{ sport.name }}</option></select></label><div class="field-pair"><label>Kode<input v-model="categoryForm.code" placeholder="PUTRA" required /></label><label>Nama<input v-model="categoryForm.name" placeholder="Putra" required /></label></div><label>Tipe<select v-model="categoryForm.competition_type"><option value="individual">Individual</option><option value="doubles">Ganda</option><option value="team">Tim</option></select></label><div class="field-pair"><label>Minimum Pemain per Team<input v-model="categoryForm.min_members" type="number" min="1" /></label><label>Maksimum Pemain per Team<input v-model="categoryForm.max_members" type="number" min="1" placeholder="Tidak dibatasi" /></label></div><label>Maksimal Team per PD<input v-model="categoryForm.default_max_teams_per_pd" type="number" min="1" max="16" required /></label></div><footer><button class="outline-button" type="button" @click="categoryModal = false">Batal</button><button class="primary-button compact" :disabled="categoryForm.processing">{{ categoryForm.processing ? 'Menyimpan…' : categoryId ? 'Simpan Perubahan' : 'Tambah Kategori' }}</button></footer></form>
      </Modal>
      <div class="table-card sport-table"><header><div><span>Daftar Master</span><h2>Kategori Lomba</h2><p>{{ activeCategories }} aktif dari {{ props.categories.length }} master kategori.</p></div><b>{{ categories.length }} data</b></header><div class="table-scroll"><table><thead><tr><th>Kategori</th><th>Tipe</th><th>Kuota Pemain</th><th>Status</th><th>Aksi</th></tr></thead><tbody><tr v-for="category in categories" :key="category.id"><td><div class="primary-cell"><strong>{{ category.name }}</strong><small>{{ category.sport.name }} · {{ category.code }} · {{ category.events_count }} kompetisi</small></div></td><td><span class="type-badge">{{ { individual: 'Individual', doubles: 'Ganda', team: 'Tim' }[category.competition_type] || category.competition_type }}</span></td><td><span class="score-value">{{ category.min_members }}–{{ category.max_members ?? '∞' }} pemain</span></td><td><span :class="['status-badge', category.is_active ? 'active' : 'inactive']">{{ category.is_active ? 'Aktif' : 'Nonaktif' }}</span></td><td><div class="row-actions"><ActionIconButton icon="edit" label="Ubah kategori" @click="openCategory(category)" /><ActionIconButton icon="power" :label="category.is_active ? 'Nonaktifkan kategori' : 'Aktifkan kategori'" :tone="category.is_active ? 'inactive' : 'active'" @click="toggleCategory(category)" /><ActionIconButton icon="delete" label="Hapus kategori" tone="danger" :disabled="category.is_active || !!category.events_count" @click="deleteCategory(category)" /></div></td></tr><tr v-if="!categories.length"><td colspan="5" class="empty-row">Data kategori tidak ditemukan.</td></tr></tbody></table></div></div>
    </section>

    <section v-else-if="tab === 'regulations'" class="regulation-master">
      <div class="section-actions"><div><strong>Regulasi</strong><span>Nomor versi dibuat otomatis. Versi lama tetap tersimpan.</span></div><button class="primary-button compact" type="button" @click="openRegulation()">Tambah Regulasi</button></div>
      <Modal :open="regulationModal" :title="regulationReadOnly ? regulationForm.title : regulationId ? 'Ubah Regulasi' : 'Tambah Regulasi'" theme="light" @close="regulationModal = false">
        <form :class="['form-card', 'regulation-form', { readonly: regulationReadOnly }]" @submit.prevent="saveRegulation">
          <header><span>{{ regulationReadOnly ? 'Detail Regulasi' : regulationId ? 'Ubah Regulasi' : 'Versi Baru Otomatis' }}</span><h2>{{ regulationReadOnly ? regulationForm.title : 'Form Regulasi Terstruktur' }}</h2><p>{{ regulationReadOnly ? 'Informasi lengkap versi regulasi.' : 'Field bertanda opsional dapat dikosongkan.' }}</p></header>
          <div class="form-body"><div class="guide-section"><strong>Informasi Utama</strong><small>Wajib diisi</small></div><label>Cabor<select v-model="regulationForm.sport_id" required><option value="">Pilih cabor</option><option v-for="sport in sports" :key="sport.id" :value="sport.id">{{ sport.name }}</option></select></label><label>Judul Regulasi<input v-model="regulationForm.title" required /></label><label>Isi Aturan Utama<textarea v-model="regulationForm.content" rows="5" required /></label><div class="guide-section"><strong>Panduan Teknis Slide 5–23</strong><small>Opsional</small></div><label>Jadwal<input v-model="regulationForm.schedule" /></label><label>Venue<select v-model="regulationForm.venue_id"><option value="">Belum ditetapkan</option><option v-for="venue in venues" :key="venue.id" :value="venue.id">{{ venue.name }} · {{ venue.city }}</option></select></label><label>Sistem Pertandingan<textarea v-model="regulationForm.system_text" rows="4" placeholder="Satu ketentuan per baris" /></label><label>Syarat Peserta<textarea v-model="regulationForm.eligibility_text" rows="4" placeholder="Satu syarat per baris" /></label><label>Kontingen dan Official<textarea v-model="regulationForm.official_note" rows="2" /></label><label>Biaya<textarea v-model="regulationForm.fee_note" rows="2" /></label><div class="field-pair"><label>Sumber Slide<input v-model="regulationForm.source_slides" placeholder="5–6" /></label><label>URL Dokumen<input v-model="regulationForm.document_url" type="url" /></label></div></div>
          <footer><button class="outline-button" type="button" @click="regulationModal = false">Tutup</button><button v-if="!regulationReadOnly" class="primary-button compact" :disabled="regulationForm.processing">{{ regulationForm.processing ? 'Menyimpan…' : regulationId ? 'Simpan Perubahan' : 'Terbitkan Versi Baru' }}</button></footer>
        </form>
      </Modal>
